1	// Utilities for use in __device__ code
2	
3	#ifndef CUDA_UTILS_CUH
4	#define CUDA_UTILS_CUH
5	
6	#include "cuda_common.h"
7	
8	// ----------------------------------------------------------------------------
9	// Packed128 data structure that forces the compiler to use 128-bit loads/stores
10	// in GPUs that support (the LDG.128 and STS.128 instructions)
11	// This is a bit similar to the use of float4 in the case of 32-bit floats, but
12	// supports arbitrary precision.
13	
14	template<class ElementType>
15	struct alignas(16) Packed128 {
16	    Packed128() = default;
17	    __device__ explicit Packed128(int4 bits) {
18	        static_assert(sizeof(bits) == sizeof(payload), "Size mismatch.");
19	        memcpy(&payload, &bits, sizeof(bits));
20	    }
21	
22	    __device__  static Packed128 constant(ElementType value) {
23	        Packed128 result;
24	        for(int k = 0; k < size; ++k) {
25	            result.payload[k] = value;
26	        }
27	        return result;
28	    }
29	    __device__ static Packed128 zeros() {
30	        return constant(0.f);
31	    }
32	    __device__ static Packed128 ones() {
33	        return constant(1.f);
34	    }
35	
36	    __device__ ElementType& operator[](int index) {
37	        return payload[index];
38	    }
39	    __device__ const ElementType& operator[](int index) const {
40	        return payload[index];
41	    }
42	    __device__ int4 get_bits() const {
43	        int4 bits;
44	        static_assert(sizeof(bits) == sizeof(payload), "Size mismatch.");
45	        memcpy(&bits, &payload, sizeof(bits));
46	        return bits;
47	    }
48	    static constexpr const size_t size = sizeof(int4) / sizeof(ElementType);
49	    ElementType payload[size];
50	};
51	
52	// load a Packed128 from an aligned memory address
53	template<class ElementType>
54	__device__ Packed128<ElementType> load128(const ElementType* address) {
55	    return Packed128<ElementType>{*reinterpret_cast<const int4*>(address)};
56	}
57	// load a Packed128 from an aligned memory address with streaming cache hint
58	template<class ElementType>
59	__device__ Packed128<ElementType> load128cs(const ElementType* address) {
60	    return Packed128<ElementType>{__ldcs(reinterpret_cast<const int4*>(address))};
61	}
62	// store a Packed128 to an aligned memory address
63	template<class ElementType>
64	__device__ void store128(ElementType* target, Packed128<ElementType> value) {
65	    *reinterpret_cast<int4*>(target) = value.get_bits();
66	}
67	// store a Packed128 to an aligned memory address with streaming cache hint
68	template<class ElementType>
69	__device__ void store128cs(ElementType* target, Packed128<ElementType> value) {
70	    __stcs(reinterpret_cast<int4*>(target), value.get_bits());
71	}
72	// store a Packed128 to an aligned memory address while caching in L2 but bypassing L1
73	template<class ElementType>
74	__device__ void store128cg(ElementType* target, Packed128<ElementType> value) {
75	    __stcg(reinterpret_cast<int4*>(target), value.get_bits());
76	}
77	
78	// short-form typedefs
79	typedef Packed128<float> f128;
80	typedef Packed128<floatX> x128;
81	
82	// ----------------------------------------------------------------------------
83	// DType support
84	
85	// enumerator to indentify the datatype of a tensor.
86	enum class DType : uint8_t {
87	    FP32, FP16, BF16
88	};
89	
90	// Given a datatype enum, returns the underlying number of bytes
91	// for a scalar of that type
92	size_t sizeof_dtype(DType type) {
93	    switch (type) {
94	        case DType::FP32:
95	            return sizeof(float);
96	        case DType::FP16:
97	            return sizeof(half);
98	        case DType::BF16:
99	            return sizeof(nv_bfloat16);
100	        default: // handle or get compiler warning
101	            fprintf(stderr, "Unknown datatype\n");
102	            exit(EXIT_FAILURE);
103	    }
104	}
105	
106	DType dtype_of(float* f) { return DType::FP32; }
107	DType dtype_of(nv_bfloat16 * f) { return DType::BF16; }
108	DType dtype_of(half * f) { return DType::FP16; }
109	
110	
111	
112	// ----------------------------------------------------------------------------
113	// Copy, cast functions
114	
115	// device functions and the kernel to cast data between types
116	template<typename Td, typename Ts>
117	__device__ Td cast_value(Ts val);
118	
119	template<>
120	__device__ float cast_value<float, float>(float val) {
121	    return val;
122	}
123	
124	template<>
125	__device__ float cast_value<float, half>(half val) {
126	    return __half2float(val);
127	}
128	
129	template<>
130	__device__ float cast_value<float, __nv_bfloat16>(__nv_bfloat16 val) {
131	    return __bfloat162float(val);
132	}
133	
134	template<typename Td, typename Ts>
135	__global__ void copy_and_cast_kernel(Td* dst, const Ts* src, size_t n, ptrdiff_t stride_dst, ptrdiff_t stride_src) {
136	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
137	    // need to try grid stride looping for more perf later
138	    if (idx < n) {
139	        dst[idx + stride_dst * blockIdx.y] = cast_value<Td, Ts>(src[idx + stride_src * blockIdx.y]);
140	    }
141	}
142	
143	// ----------------------------------------------------------------------------
144	// Warp/Block communication primitives
145	
146	// warp-level reduction for summing values
147	__device__ inline float warpReduceSum(float val) {
148	    for (int offset = 16; offset > 0; offset /= 2) {
149	        val += __shfl_xor_sync(0xFFFFFFFF, val, offset);
150	    }
151	    return val;
152	}
153	// warp-level reduction for finding the maximum value
154	__device__ inline float warpReduceMax(float val) {
155	    for (int offset = 16; offset > 0; offset /= 2) {
156	        val = fmaxf(val, __shfl_xor_sync(0xFFFFFFFF, val, offset));
157	    }
158	    return val;
159	}
160	// requires all 32 threads in the warp to be active, but should work for any block size
161	// uses non-dynamic shared memory so every call increases shared memory requirements by 128 bytes
162	// the fact it's unique shared memory allows us to avoid an extra __syncthreads() call at the end
163	// but if called inside a loop, the shared memory will be implicitly reused, so set final_sync to 1
164	using reduction_func_t = float (*) (float);
165	template<reduction_func_t warp_reduction>
166	__device__ inline float blockReduce(float val, bool final_sync=false, float out_of_bounds=0.0f) {
167	    // two reductions of up to 1024 threads:
168	    // 1) inside warp (shuffle), 2) cross-warp (shared memory), 3) inside warp (shuffle)
169	    __shared__ float shared_val[WARP_SIZE];
170	    const int lane_id = threadIdx.x % WARP_SIZE;
171	    const int warp_id = threadIdx.x / WARP_SIZE;
172	    const int num_warps = blockDim.x / WARP_SIZE;
173	
